import pytest
from playwright.sync_api import Page

BASE_URL = "http://localhost:3000"

def test_low_contrast_element_reports_violation(page: Page):
    page.goto(BASE_URL + "/login", wait_until="networkidle")

    page.evaluate("""
        const p = document.createElement('p');
        p.id = 'axe-test-low-contrast';
        p.textContent = 'Low contrast sentinel';
        p.style.cssText = 'color:#aaaaaa;background:#ffffff;font-size:14px';
        document.body.appendChild(p);
    """)

    violations = <helper_fn: run_axe>(page, rules=["color-contrast"])

    ids = [v["id"] for v in violations]
    assert "color-contrast" in ids, (
        f"Expected color-contrast violation; got: {ids}"
    )

import pytest
from playwright.sync_api import Page

BASE_URL = "http://localhost:3000"

def _inject_text(page, color, el_id):
    page.evaluate(f"""
        const el = document.getElementById('{el_id}');
        if (el) el.remove();
        const p = document.createElement('p');
        p.id = '{el_id}';
        p.textContent = 'Boundary contrast text';
        p.style.cssText = 'color:{color};background:#ffffff;font-size:14px';
        document.body.appendChild(p);
    """)

def test_contrast_ratio_at_wcag_aa_minimum_boundary(page: Page):
    page.goto(BASE_URL + "/", wait_until="networkidle")

    _inject_text(page, "#767676", "boundary-pass")
    pass_violations = <helper_fn: run_axe_on_node>(page, "#boundary-pass", rules=["color-contrast"])
    assert pass_violations == [], f"4.5:1 should pass AA; got: {pass_violations}"

    _inject_text(page, "#777777", "boundary-fail")
    fail_violations = <helper_fn: run_axe_on_node>(page, "#boundary-fail", rules=["color-contrast"])
    assert len(fail_violations) >= 1, "4.48:1 must fail AA contrast check"

import pytest
from playwright.sync_api import Page

BASE_URL = "http://localhost:3000"
REQUIRED_IDS = {"username", "password", "submit"}

def test_keyboard_navigation_traverses_all_interactive_elements(page: Page):
    page.goto(BASE_URL + "/login", wait_until="networkidle")
    page.evaluate("document.body.focus()")

    focused_ids = set()
    for _ in range(20):
        page.keyboard.press("Tab")
        el_id = page.evaluate("document.activeElement.id")
        if el_id:
            focused_ids.add(el_id)
        if REQUIRED_IDS.issubset(focused_ids):
            break

    missing = REQUIRED_IDS - focused_ids
    assert not missing, (
        f"Interactive elements not reachable via keyboard: {missing}"
    )
